/**
 * OKKI 一键同步脚本
 *
 * 自动检测浏览器状态 → 登录 → 导航TM → 提取会话元数据 → 增量拉消息
 *
 * 用法：node scripts/sync_okki.js
 *
 * 适用所有场景：
 * - 刚开机/Chrome没开/没登录 → 自动启动Chrome → 等你登录 → 继续
 * - Chrome开着+已登录+在TM页 → 直接抓取
 * - Chrome开着但不在TM页 → 自动导航
 */

const { chromium } = require('playwright');
const fs = require('fs');
const path = require('path');
const http = require('http');

const PROFILE = 'C:\\Users\\Administrator\\AppData\\Local\\Google\\Chrome\\User Data\\Profile 4';
const DATA_DIR = path.join(__dirname, '..', 'data');
const CHAT_DIR = path.join(DATA_DIR, 'chat_history');
const CDP_URL = 'http://localhost:9222';
const MSG_COUNT = 50;
const MAX_PAGES = 20;

// ===================== 工具函数 =====================

function ts() { return new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19); }
function log(msg) { console.log(`[${new Date().toLocaleTimeString()}] ${msg}`); }
function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

function sanitizeFilename(cid) {
  return cid.replace(/[<>:"/\\|?*#@]/g, '_').substring(0, 200);
}

// ===================== CDP 端口检测 =====================

function checkCdpPort() {
  return new Promise((resolve) => {
    const req = http.get('http://127.0.0.1:9222/json/version', (res) => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          resolve(!!json.webSocketDebuggerUrl);
        } catch (e) { resolve(false); }
      });
    });
    req.on('error', () => resolve(false));
    req.setTimeout(2000, () => { req.destroy(); resolve(false); });
  });
}

// ===================== 主流程 =====================

async function main() {
  let browser;
  let page;
  let useCdp = false;

  // ---- Step 1: 启动/连接浏览器 ----
  const cdpAvailable = await checkCdpPort();
  if (cdpAvailable) {
    log('检测到 CDP 端口，尝试连接已有 Chrome...');
    try {
      browser = await chromium.connectOverCDP(CDP_URL);
      const pages = browser.contexts()[0]?.pages() || [];
      page = pages.find(p => p.url().includes('xiaoman') || p.url().includes('onetalk'));
      if (!page) {
        page = await browser.contexts()[0].newPage();
      }
      useCdp = true;
      log(`CDP 已连接。当前页面: ${page.url()}`);
    } catch (e) {
      log(`CDP 连接失败: ${e.message}，改用独立启动模式`);
    }
  }

  if (!browser) {

