40	function determineQuality(e, fullCustText, fullConvText) {
41	  const ft = (fullConvText || '').toLowerCase();
42	  const ct = (fullCustText || '').toLowerCase();
43	
44	  // ── 全量对话提取数量信息（从客户消息提取更可靠）──
45	  // 支持英/中/法/西/阿语常见数量单位
46	  const qtyMatches = ct.match(/(\d{3,})\s*(pcs|pieces|units?|unit[ée]s?|件|piece|pc|pce|paires?|douzaines?|qt[ée]|quantit[ée]s?|sets?|ensembles?)/gi) || [];
47	  let maxQty = 0;
48	  for (const qm of qtyMatches) {
49	    const n = parseInt(qm.match(/\d+/)[0], 10);
50	    if (n > maxQty) maxQty = n;
51	  }
52	
53	  // ── 母婴品类信号（修正 D 误判用）──
54	  const isBabyRelated = /(baby|kid|child|infant|toddler|newborn|bib|romper|bodysuit|onesie|swaddle|sleepsuit|blanket|crib|stroller|nursery|童|婴|幼|卡通|cartoon)/i.test(ft);
55	
56	  // ── S 级信号（严格版 — 优先用 ct 即客户消息）──
57	  const sSignals = [];
58	  // 品牌/ODM: 明确且有意图的组合（含法/西/阿语）
59	  if (/(odm|oem|private\s*(label|brand)|own\s*(brand|design|label)|custom\s*(logo|packaging|packing|design|label|box|bag|tag)|hangtag|barcode|brand\s*name|brand\s*label|your\s*logo|my\s*logo|our\s*logo|marque|personnalis[ée]|personnaliser|[ée]tiquette.*perso|logo.*perso|votre.*logo|mon.*logo|mon.*design|mon.*propre)/i.test(ct))
60	    sSignals.push('品牌/ODM');
61	  // 分销渠道: 明确平台或分销语言（含法/西/阿语）
62	  if (/(amazon|walmart|shopify|distributor|retail\s*(chain|store|shop)|wholesale\s*(channel|distributor|business)|sell\s*(on|through|in)\s*(amazon|walmart|shopify|online)|revendeur|distributeur|vendre.*(sur|en ligne|amazon)|boutique.*(en ligne|online)|tienda.*(online|en.linea)|mayorista)/i.test(ct))
63	    sSignals.push('分销渠道');
64	  if (maxQty >= 500) sSignals.push('大批量(' + maxQty + '件)');
65	  // 公司资料: 客户主动分享
66	  if (/(here.*(is|are).*(website|store|shop|link)|check.*(my|our).*(website|store|shop|page)|this\s*is\s*(my|our).*(website|store|shop)|find\s*(us|me).*(on|at).*(website|store))/i.test(ct) ||
67	      /(https?:\/\/|www\.\w+\.(com|net|org|co))/i.test(ct))
68	    sSignals.push('公司资料');
69	  // 复购: 明确的复购/追加语言
70	  if (/(reorder|restock|another\s*(order|shipment|batch|container)|second\s*(order|shipment)|repeat\s*order|buy\s*more|order\s*more|send\s*more|top\s*up)/i.test(ct))
71	    sSignals.push('复购信号');
72	
73	  // ── A 级附加信号 ──
74	  const aSignals = [];
75	  if (maxQty >= 200 && maxQty < 500) aSignals.push('中批量(' + maxQty + '件)');
76	  if (/(500.*ok|500.*fine|moq.*(ok|fine|accept|no.*problem)|accept.*(moq|500|minimum)|can.*(take|do|handle).*500|ok.*(with|about).*(500|moq)|no.*problem.*(500|moq)|(je|nous).*(prends?|commande|veux|voudrais).*500|500.*(va|marche|ok|d'accord)|pas.*probl[èe]me.*500)/i.test(ct))
77	    aSignals.push('MOQ已接受');
78	  if (/(sample.*(sent|shipped|sending|ready|prepar|made|done|making|proceed)|(sent|shipped|send|ready).*sample|样品.*(寄|发|做|准备))/i.test(ft))
79	    aSignals.push('样品已寄/在准备');
80	  if (e.realMsgs >= 15 && e.customerMsgs >= 3)
81	    aSignals.push('深度沟通(' + e.realMsgs + '条)');
82	  if (/(price.*(high|expensive|too much|negot|discount|lower|reduce|better.*price|best.*price|last.*price|final.*price)|便宜|贵|折扣|降价|便宜点|r[ée]duction|remise|rabais|n[ée]goci|trop.*(cher|[ée]lev[ée]|haut)|moins.*cher|prix.*(bas|moins)|descuento|rebaja|caro|muy.*caro|barato)/i.test(ct))
83	    aSignals.push('价格谈判');
84	  if (/(bsci|iso|audit|certif|认证|factory.*(video|tour|visit)|验厂|验货)/i.test(ct))
85	    aSignals.push('关心认证/验厂');
86	  if (/(freight|shipping|运费|物流|delivery.*cost|ship.*cost|transport.*cost|dhl|fedex|ups|aramex|courier|by sea|by air|container)/i.test(ct) && e.hasQuantity)
87	    aSignals.push('讨论运费+数量');
88	
89	  // ── C 级降级信号 ──
90	  const cSignals = [];
91	  if (/(for myself|for my kid|for my baby|personal use|自用|送人|gift.*for|for.*gift|personal.*purchase|own.*use|just.*for.*(me|myself|my.*kid|my.*baby)|pour moi|pour mon|personnel|usage.*personnel|uso.*personal|para mi)/i.test(ct))
92	    cSignals.push('个人自用');
93	  if (/(just.*(few|a few|small|little|some)|small.*(quantity|order|business|little)|little.*(order|quantity|business|bit)|tiny|only.*(need|want).*\d{1,2}\s*(pcs|pieces)|petit.*(quantit[ée]|commande)|peu.*(de|commande)|juste.*(quelques|un peu)|solo.*(pocos?|pocas?|unos?|unas?))/i.test(ct))
94	    cSignals.push('小批量暗示');
95	  if (maxQty > 0 && maxQty <= 50) cSignals.push('明确小量(' + maxQty + '件)');
96	  if (e.realMsgs <= 3 && e.customerMsgs === 1 && !e.hasPrice && !e.hasSample && !e.hasQuantity)
97	    cSignals.push('单次浅层互动');
98	
99	  // ── D 级判定（修正版）──
100	  if (e.realMsgs <= 2 && e.customerMsgs === 0)
101	    return { grade: 'D', label: '无关/废弃', reason: '仅系统消息/无真实对话', auto: true };
102	
103	  // 品类不匹配：成人/非母婴 AND NOT 母婴相关
104	  if (/(adult|成人|men.*wear|男装|sexy|lingerie|women.*dress|fashion.*(dress|wear)|wedding|evening.*(dress|wear)|not.*(baby|kid|child))/i.test(ft) && !isBabyRelated)
105	    return { grade: 'D', label: '无关', reason: '品类不匹配(非母婴)', auto: true };
106	
107	  // 非采购意图
108	  if (/(转让|加盟|franchise|找.*工作|job|hiring|recruit|sell.*business)/i.test(ft) && e.realMsgs <= 5)
109	    return { grade: 'D', label: '无关', reason: '非采购意图', auto: true };
110	
111	  // ── 综合定级 ──
112	  const totalSSignals = sSignals.length;
113	  const totalASignals = aSignals.length;
114	  const totalCSignals = cSignals.length;
115	
116	  // S: 2+ 个S级信号
117	  if (totalSSignals >= 2)
118	    return { grade: 'S', label: '战略客户', reason: sSignals.join('+'), auto: true };
119	
120	  // A: 1个S级信号 或 (2+个A级信号+有实质互动)
121	  if (totalSSignals >= 1)
122	    return { grade: 'A', label: '优质客户', reason: [...sSignals, ...aSignals].filter(Boolean).join('+') || sSignals.join('+'), auto: true };
123	
124	  if (totalASignals >= 2 && e.realMsgs >= 5)
125	    return { grade: 'A', label: '优质客户', reason: aSignals.join('+'), auto: true };
126	
127	  // C: 明确降级信号 + 无上升信号
128	  if (totalCSignals >= 2 && totalSSignals === 0 && totalASignals <= 1)
129	    return { grade: 'C', label: '低价值', reason: cSignals.join('+'), auto: true };
130	
131	  if (maxQty > 0 && maxQty <= 30 && totalSSignals === 0 && totalASignals === 0)
132	    return { grade: 'C', label: '低价值', reason: '明确小量≤30件', auto: true };
133	
134	  // 单次互动无后续 → C（而非B）
135	  if (e.realMsgs <= 4 && e.customerMsgs >= 1 && e.customerMsgs <= 2 && !e.hasPrice && !e.hasSample && !e.hasQuantity && typeof e.lastCustomerMsgDays === 'number' && e.lastCustomerMsgDays > 30)
136	    return { grade: 'C', label: '低价值', reason: '单次互动+30天无后续', auto: true };
137	
138	  // 浅互动+长期沉默 → C（"问完消失"模式）
139	  if (e.realMsgs <= 5 && e.customerMsgs <= 2 && totalSSignals === 0 && totalASignals <= 1 && typeof e.lastCustomerMsgDays === 'number' && e.lastCustomerMsgDays > 60)
140	    return { grade: 'C', label: '低价值', reason: '浅互动+长期沉默(' + e.lastCustomerMsgDays + 'd)', auto: true };
141	
