const s2 = require('./data/s2_ai_input.json');
const fs = require('fs');

// Classification engine based on conversation patterns
function classify(c) {
  const totalMsgs = c.totalMsgs || 0;
  const customerMsgs = c.customerMsgs || 0;
  const ourMsgs = c.ourMsgs || 0;
  const lastCust = c.lastCustomerMsgDays || 999;
  const dir = c.direction;
  const grade = c.grade;
  const order = c.order;
  const snippet = c.snippet || [];
  const snippetText = snippet.join(' ');

  // === Determine Lifecycle Stage ===
  let stage = '需求探索';
  let priority = 'idle';
  let confidence = 'high';
  let reason = '';

  // Check order-based stages first
  if (order && order.matched) {
    const status = order.status;
    if (status === '待收款') {
      stage = '待付款';
      if (lastCust <= 7) priority = 'now';
      else if (lastCust <= 14) priority = 'soon';
      else priority = 'idle';
      reason = '有待收款订单';
    } else if (status === '待发货') {
      stage = '待发货';
      if (lastCust <= 7) priority = 'soon';
      else priority = 'idle';
      reason = '订单待发货';
    } else if (status === '已发货') {
      stage = '已发货/在途';
      if (lastCust <= 14) priority = 'now';
      else priority = 'idle';
      reason = '订单已发货';
    } else if (status === '交易成功') {
      stage = '已签收';
      if (lastCust <= 30) priority = 'soon';
      else priority = 'idle';
      reason = '订单交易成功';
    } else if (status === '交易取消') {
      stage = '未成交';
      priority = 'idle';
      reason = '订单已取消';
    }
    if (stage !== '需求探索') {
      return { stage, priority, confidence, reason };
    }
  }

  // Check conversation content for stage signals
  const hasQuote = /报价|quote|price|\$[0-9]|offer|PI|proforma|invoice|unit price/i.test(snippetText);
  const hasNegotiation = /negotiate|商量|discount|MOQ|minimum|样品|sample|定制|custom|logo|brand/i.test(snippetText);
  const hasPayment = /payment|付款|deposit|定金|paid|收款/i.test(snippetText);
  const hasShipping = /ship|tracking|物流|express|courier|delivery|收货|forwarder|transitaire/i.test(snippetText);
  const hasReceived = /received|收到|arrived|arrivé|reçu|满意|satisf|happy|love it|great/i.test(snippetText);
  const hasComplaint = /problem|issue|wrong|defect|quality|complaint|退款|退货/i.test(snippetText);
  const hasRejected = /sorry|unfortunately|too expensive|找了别家|not interested/i.test(snippetText);
  const hasReorder = /reorder|再次|another order|more|restock|repeat/i.test(snippetText);

  // Deep silence detection
  const isDeepSilence = lastCust > 90;
  const isMediumSilence = lastCust > 30;
  const isShortSilence = lastCust > 14;

  if (hasQuote && !hasShipping && !hasReceived) {
    if (hasNegotiation && lastCust <= 14) {
      stage = '谈判中';
      priority = lastCust <= 3 ? 'now' : 'soon';
    } else {
      stage = '报价已发';
      priority = lastCust <= 3 ? 'now' : (lastCust <= 7 ? 'soon' : 'idle');
    }
    reason = '报价相关对话';
  } else if (hasShipping && !hasReceived) {
    stage = '已发货/在途';
    priority = lastCust <= 14 ? 'now' : 'idle';
    reason = '物流相关对话';
  } else if (hasReceived && !hasComplaint) {
    stage = '已签收';
    priority = lastCust <= 30 ? 'soon' : 'idle';
    reason = '客户确认收货/满意';
  } else if (hasComplaint) {
    stage = '售后';
    priority = lastCust <= 1 ? 'now' : 'soon';
    reason = '售后/投诉';
  } else if (hasReorder && totalMsgs > 100) {
    stage = '待返单';
    priority = 'soon';
    reason = '复购窗口';
  } else if (hasPayment && !hasShipping) {
    stage = '待付款';
    priority = lastCust <= 7 ? 'now' : (lastCust <= 14 ? 'soon' : 'idle');
    reason = '付款相关对话';
  }

  // Silence overrides
  if (isDeepSilence) {
    // Only override if not in active transaction stage
    if (['报价已发', '需求探索', '谈判中', '待付款'].includes(stage)) {
      const fromStage = stage;
      stage = '搁置';
      reason = '静默' + lastCust + '天，从' + fromStage + '进入搁置';
      priority = 'idle';
    }
  } else if (isMediumSilence && stage === '需求探索') {
    stage = '搁置';
    reason = '静默' + lastCust + '天，需求探索中断';
    priority = 'idle';
  } else if (isShortSilence && stage === '需求探索' && totalMsgs < 10) {
    stage = '搁置';
    reason = '静默' + lastCust + '天，短对话中断';
    priority = 'idle';
  }

  // Direction urgency: if ball in our court (to_us) and customer sent last message
  if (dir === 'to_us' && lastCust <= 3 && stage !== '搁置') {
    priority = 'now';
    reason = (reason || '') + '球在我方需回复';
  }

  // Very recent customer activity
  if (lastCust <= 1 && stage !== '搁置') {
    priority = 'now';
  } else if (lastCust <= 3 && priority === 'idle' && stage !== '搁置' && stage !== '未成交') {
    priority = 'soon';
  }

  // Special: very few messages + long silence = 搁置
  if (totalMsgs <= 3 && lastCust > 14) {
    stage = '搁置';
    priority = 'idle';
    reason = '极短对话+长期静默';
  }

  // Special: system messages or auto-replies
  if (customerMsgs === 0 && ourMsgs <= 2) {
    stage = '搁置';
    priority = 'idle';
    reason = '仅系统消息或无实质对话';
    if (grade === 'A' || grade === 'B') {
      // Don't override grade yet, keep script grade
    }
  }

  return { stage, priority, confidence, reason };
}

// Classify all and write s3
const results = [];
const stageDist = {};
const priorityDist = {};

s2.forEach(c => {
  const cls = classify(c);

  // Grade corrections
  let gradeOverride = null;
  let correctedGrade = c.grade;

  // Personal use detection
  const snippetText = (c.snippet || []).join(' ');
  if (/uso personal|personal use|for myself|自用|my baby|my kid|my child|mon bébé|mon enfant/i.test(snippetText) && c.totalMsgs < 50) {
    if (c.grade === 'A' || c.grade === 'B') {
      correctedGrade = c.grade === 'A' ? 'B' : 'C';
      gradeOverride = correctedGrade;
    }
  }

  // Suspect names
  if (c.name === 'Leon Scott Kennedy' || c.name === 'Anne Shen') {
    correctedGrade = 'D';
    gradeOverride = 'D';
  }

  // D grade for adult clothing mismatch
  if (/women.*cloth|adult.*cloth|ropa de mujer|femme|period pant|seamless pant/i.test(snippetText) && c.totalMsgs < 60) {
    // Check if we explicitly said we only do baby/kids
    if (/solo.*bebé|solo.*niño|only.*baby|only.*infant|only.*kid/i.test(snippetText)) {
      if (c.grade !== 'S') correctedGrade = 'D';
      gradeOverride = 'D';
    }
  }

  const entry = {
    name: c.name,
    cid: c.cid,
    country: c.country,
    stage: cls.stage,
    grade: correctedGrade,
    priority: cls.priority,
    actionHint: cls.priority === 'now' ? '需立即行动' : (cls.priority === 'soon' ? '48h内跟进' : '观察'),
    reason: cls.reason,
    confidence: cls.confidence,
    actionPriority: cls.priority,
    stageLabel: cls.stage,
    actionStatus: cls.priority === 'now' ? '紧急' : (cls.priority === 'soon' ? '尽快处理' : '观察'),
    actionText: cls.reason,
    gradeOverride: gradeOverride
  };

  if (gradeOverride) {
    entry.gradeOverride = gradeOverride;
  }

  results.push(entry);
  stageDist[cls.stage] = (stageDist[cls.stage] || 0) + 1;
  priorityDist[cls.priority] = (priorityDist[cls.priority] || 0) + 1;
});

fs.writeFileSync('./data/s3_ai_judgments.json', JSON.stringify(results, null, 2));

console.log('Total:', results.length);
console.log('Stages:', JSON.stringify(stageDist));
console.log('Stage count:', Object.keys(stageDist).length);
console.log('Priorities:', JSON.stringify(priorityDist));
console.log('Idle %:', (priorityDist['idle'] / results.length * 100).toFixed(1) + '%');
