  if (c.stage === '搁置' && d >= 30 && d <= 90 && (c.grade === 'S' || c.grade === 'A') && s.totalMsgs >= 30) return true;

  // 3. to_us direction (ball in our court)
  if (s.direction === 'to_us') return true;

  // 4. 待付款 + >14d silence
  if (c.stage === '待付款' && d > 14) return true;

  return false;
});

