  const da = s2Map[a.cid]?.lastCustomerMsgDays ?? 0;
  const db = s2Map[b.cid]?.lastCustomerMsgDays ?? 0;
  return db - da;
});

focus.forEach(c => {
  const s = s2Map[c.cid];
  console.log(c.name + ' | ' + c.country + ' | ' + c.grade + ' | ' + c.stage + 
    ' | ' + (s?.lastCustomerMsgDays ?? '?') + 'd | msgs:' + (s?.totalMsgs ?? '?') +
    ' | ' + (s?.direction ?? '?'));
});
